code = """import json

# Load the EMA results
result_path = locals()['var_functions.execute_python:60']
with open(result_path, 'r') as f:
    ema_data = json.load(f)

cpc_ema_results = ema_data['cpc_ema_results']

# Load the CPC definition results
result_path_cpc = locals()['var_functions.query_db:92']
with open(result_path_cpc, 'r') as f:
    cpc_definitions = json.load(f)

# Create a mapping from base symbol to title
base_symbol_to_title = {}
for item in cpc_definitions:
    base_symbol = item['base_symbol']
    title = item['titleFull']
    if base_symbol not in base_symbol_to_title:
        base_symbol_to_title[base_symbol] = title

print("CPC Technology Areas in Germany - Top 15 by Exponential Moving Average")
print("=" * 80)
print("Analysis of patents granted in second half of 2019")
print()

# Get top 15 CPC codes by EMA
top_15_cpc = sorted(cpc_ema_results.items(), key=lambda x: x[1]['best_ema'], reverse=True)[:15]

results = []
for i, (code, data) in enumerate(top_15_cpc, 1):
    # Get the title for this base symbol
    title = base_symbol_to_title.get(code, "Title not found")
    
    result_item = {
        'cpc_level4_code': code,
        'title_full': title,
        'best_year': data['best_year'],
        'ema_value': round(data['best_ema'], 4),
        'patent_count': data['actual_count_in_best_year']
    }
    results.append(result_item)
    
    print(f"{i:2d}. CPC Code: {code}")
    print(f"    Title: {title[:80]}..." if len(title) > 80 else f"    Title: {title}")
    print(f"    Best Year: {data['best_year']}")
    print(f"    EMA Value: {data['best_ema']:.4f}")
    print(f"    Patents Filed: {data['actual_count_in_best_year']}")
    print()

print(f"Total CPC level 4 codes analyzed: {len(cpc_ema_results)}")
print(f"Patents in second half 2019: {ema_data.get('sh_2019_patents_count', 0)}")

# Save final results
final_output = {
    'summary': {
        'total_cpc_analyzed': len(cpc_ema_results),
        'patents_in_second_half_2019': ema_data.get('sh_2019_patents_count', 0),
        'analysis_years': '2000-2024'
    },
    'top_cpc_areas': results
}

print('__RESULT__:')
print(json.dumps(final_output))"""

